/// <summary>
/// The <c>ETGPurchRegisterReportDP</c> class is the report data provider class for Purchase register report
/// </summary>
[
    SRSReportQueryAttribute(queryStr(ETGPurchRegisterReportQuery)),
    SRSReportParameterAttribute(classStr(Etg_registerPurchContract))    
        ]
class Etg_RegisterPurchReportDP extends SrsReportDataProviderPreProcessTempDB
{

        Etg_registerPurchTemp       Etg_registerPurchTemp;              
        Etg_registerPurchContract  contract;
        FromDate                        fromDate;
        ToDate                          toDate;
        DimensionSetName                financialDimSet;
        NoYes                           isDetailReport;
        EcoResConfigurationFlag         viewConfigId;
        EcoResSizeFlag                  viewInventSizeId;
        EcoResColorFlag                 viewInventColorId;
        EcoResStyleFlag                 viewInventStyleId;
        InventSiteIdFlag                viewInventSiteId;
        InventLocationIdFlag            viewInventLocationId;
        WHSLicensePlateFlag             viewLicensePlate;
        InventLocationIdFlag            viewWMSLocationId;
        WHSInventStatusFlag             viewInventStatus;
        InventBatchIdFlag               viewInventBatchId;
        InventSerialIdFlag              viewInventSerialId;
        InventOwnerIdFlag               viewInventOwnerId;
        utcDateTime                     utcFromDate, utcToDate;
        PurchId                         currentPurchId;
        RefRecId                        currentPurchLine;

        PurchTable                      purchTable;
        PurchLine                       purchLine;
        InventDim                       inventDim;
        //ETG_VendInvBillOfLading         vendInvBOL;



}

Method.Source:
[SRSReportDataSetAttribute(tablestr(Etg_registerPurchTemp))]
public Etg_registerPurchTemp getEtg_registerPurchTemp()
    {
        select Etg_registerPurchTemp;
        return Etg_registerPurchTemp;
    }

public void processReport()
    {
        this.initContract();
        if (ETGACFParameters::find().EnablePurchRegisterReportChanges == NoYes::Yes)
        {
            this.insertDataACF();
        }
        else
        {
            this.insertData();
        }

    }

/// <summary>
    ///    Parses the report parameters and fills the <c>ETGPurchRegisterReportTmp</c> and <c>ETGPurchRegisterReportTmp</c>
    ///    tables with data.
    /// </summary>
    public void initContract()
    {
        contract                = this.parmDataContract() as Etg_registerPurchContract;
        fromDate                = contract.parmFromDate();
        toDate                  = contract.parmToDate();
        financialDimSet         = contract.parmFinancialDimSet();
        isDetailReport          = contract.parmIsDetailReport();
        viewConfigId            = contract.parmViewConfigId();
        viewInventSizeId        = contract.parmViewInventSizeId();
        viewInventColorId       = contract.parmViewInventColorId();
        viewInventStyleId       = contract.parmViewInventStyleId();
        viewInventSiteId        = contract.parmViewInventSiteId();
        viewInventLocationId    = contract.parmViewInventLocationId();
        viewLicensePlate        = contract.parmViewLicensePlateId();
        viewWMSLocationId       = contract.parmViewWMSLocationId();
        viewInventStatus        = contract.parmViewInventStatus();
        viewInventBatchId       = contract.parmViewInventBatchId();
        viewInventSerialId      = contract.parmViewInventSerialId();
        viewInventOwnerId       = contract.parmViewInventOwnerId_RU();
    }

/// <summary>
///    inserting data useing parm query
/// </summary>
public void insertData()
{
    QueryRun                        queryRun;
    VendTable                       vendAccountTable;
    VendTrans                       vendTrans;
    purchAgreementHeader            purchAgreementHeader;
    AgreementHeader                 agreementHeader;
    AgreementLine                   agreementLine;
    SalesAgreementHeader            salesAgreementHeader;
    ETG_purchTableTrade             ETG_purchTableTrade;
    VendPackingSlipJour             vendPackingSlipJour;
    VendPackingSlipTrans            vendPackingSlipTrans;
    VendInvoiceJour                 vendInvoiceJour;
    VendInvoiceTrans                vendInvoiceTrans;
    ETG_OrderType                   orderType;
    Query                           query = this.parmQuery();
    InventTrans                     inventTrans;
    ETG_PurchaseAgreementHeader     eTG_PurchaseAgreementHeader;
    ETG_AgreementType               AgreementType;
    DimensionAttributeValueSetStorage dimStorage;
    CompanyInfo                       companyInfo;
    InventTable                       inventTable;
    Ledger ledgerOrg;
    ExchangeRateCurrencyPair exchangeRateCurrencyPair;
    ExchRate exchRate, exchValueCount;
    real unitPrice;
    utcFromDate = DateTimeUtil::newDateTime(fromDate, 0);
    utcToDate   = DateTimeUtil::newDateTime(toDate, 86400);

    while select vendInvoiceJour where vendInvoiceJour.InvoiceDate >= fromDate
                             &&  vendInvoiceJour.InvoiceDate <= todate
                             &&  vendInvoiceJour.purchasetype == purchasetype::Purch
  if(vendInvoiceJour)
    {

        Etg_registerPurchTemp.clear();

        Etg_registerPurchTemp.InvoiceNumber      = VendInvoiceJour.InvoiceId;
        Etg_registerPurchTemp.ETGVoucher         = VendInvoiceJour.LedgerVoucher;
        Etg_registerPurchTemp.TransDate          = VendInvoiceJour.InvoiceDate;
        Etg_registerPurchTemp.Quantity           = VendInvoiceJour.Qty;
        Etg_registerPurchTemp.AmountInTransactionCurrency = VendInvoiceJour.InvoiceAmount;
        Etg_registerPurchTemp.AmountInAccountingCurrency  = VendInvoiceJour.InvoiceAmountMST;




        if(VendInvoiceJour.CurrencyCode == "USD")
        {
            Etg_registerPurchTemp.AmountInReportingCurrency  = VendInvoiceJour.InvoiceAmount;
            Etg_registerPurchTemp.ExchangeRate = VendInvoiceJour.ExchRate / 100;
        }
        else
        {
            select firstonly ledgerOrg
        where ledgerOrg.Name == curExt();

            select firstonly exchangeRateCurrencyPair
        where exchangeRateCurrencyPair.ExchangeRateType == ledgerOrg.DefaultExchangeRateType
           && exchangeRateCurrencyPair.FromCurrencyCode == "USD"
           && exchangeRateCurrencyPair.ToCurrencyCode == VendInvoiceJour.CurrencyCode;

            if(exchangeRateCurrencyPair)
            {
                exchRate = exchangeRate::findByDate(exchangeRateCurrencyPair.RecId,
                               VendInvoiceJour.InvoiceDate).ExchangeRate;

                Etg_registerPurchTemp.ExchangeRate = exchRate/100;
            }
            else
            {
                exchRate = 0;
            }

            if(exchRate == 0)
            {
                Etg_registerPurchTemp.AmountInReportingCurrency  = 0.00;
            }
            else
            {

                exchValueCount = exchRate / 100.0;

                Etg_registerPurchTemp.AmountInReportingCurrency  = round(VendInvoiceJour.InvoiceAmount / exchValueCount,0.01);
                  //Etg_registerPurchTemp.AmountInReportingCurrency  = ((VendInvoiceJour.InvoiceAmount) / exchRate)/100;
            }
        }



        Etg_registerPurchTemp.VendorCode         = VendInvoiceJour.InvoiceAccount;
        Etg_registerPurchTemp.VendorName         = vendTable::find(VendInvoiceJour.InvoiceAccount).name();
        Etg_registerPurchTemp.TaxAmount          = VendInvoiceJour.SumTax;
        Etg_registerPurchTemp.TaxGroup           = VendInvoiceJour.TaxGroup;
        Etg_registerPurchTemp.PONumber           = VendInvoiceJour.PurchId;
        Etg_registerPurchTemp.Currency           = VendInvoiceJour.CurrencyCode;
        Etg_registerPurchTemp.BillOfLadingNumber = VendInvoiceJour.ETG_BLnumber;
        Etg_registerPurchTemp.IncoTerms          = VendInvoiceJour.DlvTerm;

        select firstonly purchTable
      where purchTable.PurchId ==  VendInvoiceJour.PurchID;

        Etg_registerPurchTemp.VendorGroupName          = VendGroup::find(purchTable.VendGroup).Name;

        select firstonly ETG_purchTableTrade
      where ETG_purchTableTrade.PurchId == purchTable.PurchID;

        Etg_registerPurchTemp.Remarks           = ETG_purchTableTrade.Remarks;
        Etg_registerPurchTemp.PortofLoading     = ETG_purchTableTrade.PortOfLoadingDesc;
        Etg_registerPurchTemp.PortOfDischarge   = ETG_purchTableTrade.PortOfDischargeDesc;
        //Etg_registerPurchTemp.Country           = ETG_purchTableTrade.CountryOfOriginOfGoods;
       // Etg_registerPurchTemp.SalesDestination  s= ETG_purchTableTrade.CountryOfFinalDestination;
        //Etg_registerPurchTemp.IncoTerms         = ETG_SalesTableTrade;
        //Etg_registerPurchTemp.BillOfLadingNumber = purchTable.remarks;


        select firstonly purchAgreementHeader
      where purchAgreementHeader.RecId ==  purchTable.MatchingAgreement;

        select eTG_PurchaseAgreementHeader
      where eTG_PurchaseAgreementHeader.PurchAgreementId == PurchAgreementHeader.PurchNumberSequence;

        Etg_registerPurchTemp.PurchaseContractNumber   = purchAgreementHeader.PurchNumberSequence;
        Etg_registerPurchTemp.ContractOrderType        = eTG_PurchaseAgreementHeader.AgreementType;

      //  select firstonly inventTrans
      //where inventTrans.InvoiceId ==   VendInvoiceJour.InvoiceId;

        select firstonly vendInvoiceTrans
      where vendInvoiceTrans.InvoiceId == vendInvoiceJour.InvoiceId 
            && vendInvoiceTrans.PurchID == vendInvoiceJour.PurchId;

        select firstonly vendPackingSlipTrans
    where vendPackingSlipTrans.InventTransId == vendInvoiceTrans.InventTransId
       && vendPackingSlipTrans.OrigPurchid == vendInvoiceTrans.PurchId;

        Etg_registerPurchTemp.GRNNumber          = vendPackingSlipTrans.PackingSlipId;

        Etg_registerPurchTemp.Commodity          = vendInvoiceTrans.ItemId;
        Etg_registerPurchTemp.UOM                = vendInvoiceTrans.PurchUnit;
        Etg_registerPurchTemp.UnitPrice          = vendInvoiceTrans.PurchPrice;
        if(Etg_registerPurchTemp.UnitPrice == 0.00)
        {                
            unitPrice = Etg_registerPurchTemp.AmountInTransactionCurrency - Etg_registerPurchTemp.TaxAmount;
            Etg_registerPurchTemp.UnitPrice = unitPrice / Etg_registerPurchTemp.Quantity;
        }
        if(purchTable.InclTax == NoYes::Yes)
        {
            Etg_registerPurchTemp.PurchaseValue  = (Etg_registerPurchTemp.UnitPrice * VendInvoiceJour.Qty) - Etg_registerPurchTemp.TaxAmount;
        }
        else
        {
            Etg_registerPurchTemp.PurchaseValue  = Etg_registerPurchTemp.UnitPrice * VendInvoiceJour.Qty;
        }
       // Etg_registerPurchTemp.PurchaseValueInLocalCurrency = (Etg_registerPurchTemp.PurchaseValue * vendInvoiceJour.ExchRate) / 100;
        Etg_registerPurchTemp.PurchaseValueInLocalCurrency = round((Etg_registerPurchTemp.PurchaseValue * vendInvoiceJour.ExchRate) / 100, 0.01);

        select firstonly inventdim
      where inventdim.inventDimId ==   vendInvoiceTrans.InventDimId; //inventTrans.inventDimId;

        Etg_registerPurchTemp.Brand       = inventDim.InventStyleId;
        Etg_registerPurchTemp.Grade       = inventDim.configId;
        Etg_registerPurchTemp.Size        = inventDim.InventSizeId;
        Etg_registerPurchTemp.Site        = inventDim.InventSiteId;
        Etg_registerPurchTemp.Origin      = inventDim.InventColorId;
        Etg_registerPurchTemp.BatchNumber = inventDim.inventBatchId;
        Etg_registerPurchTemp.Location    = inventDim.wMSLocationId;
        Etg_registerPurchTemp.WareHouse   = inventDim.InventLocationId;
        Etg_registerPurchTemp.SerialNumber   = inventDim.inventSerialId;

        //Etg_registerPurchTemp.InventLocationName   = InventLocation::find(inventDim.InventLocationId).Name;
        dimStorage = DimensionAttributeValueSetStorage::find(vendInvoiceJour.DefaultDimension);
        Etg_registerPurchTemp.Vertical    =  dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName('Vertical').RecId);
        Etg_registerPurchTemp.SubVertical    =  dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName('SubVertical').RecId);
        Etg_registerPurchTemp.ProfitCenter    =  dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName('ProfitCenter').RecId);
        Etg_registerPurchTemp.BusinessUnit    =  dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName('BusinessUnit').RecId);

        select * from companyInfo where companyInfo.DataArea == curExt();

        Etg_registerPurchTemp.ETGCompanyName = companyInfo.name();
        Etg_registerPurchTemp.ETGCompanyLogo = FormLetter::companyLogo();

        select * from inventTable where inventTable.ItemId == vendInvoiceTrans.ItemId; //inventTrans.ItemId;

        Etg_registerPurchTemp.ETGMainCommodity = inventTable.ETGCommodity;
        Etg_registerPurchTemp.ETGSubCommodity  = inventTable.ETGSubCommodity;
        Etg_registerPurchTemp.ETGVesselName    = ETG_purchTableTrade.VesselName;

        int num = mthOfYr(Etg_registerPurchTemp.TransDate);
        Etg_registerPurchTemp.ETGMonth = mthName(num);
        Etg_registerPurchTemp.ETGItemName      = EcoResProductTranslation::findByProductLanguage(InventTable::find(vendInvoiceTrans.ItemId).Product, SystemParameters::getSystemLanguageId()).Name;

        UnitOfMeasureSymbol cleanUOM = strLTrim(strRTrim(vendInvoiceTrans.PurchUnit));

        switch (cleanUOM)
        {
            case 'MT':
                Etg_registerPurchTemp.QuantityInMetricTon = Etg_registerPurchTemp.Quantity;
                break;
            case 'PCS':
                Etg_registerPurchTemp.QuantityInMetricTon = Etg_registerPurchTemp.Quantity * 1.0;
                break;
            case 'KG':
                Etg_registerPurchTemp.QuantityInMetricTon = Etg_registerPurchTemp.Quantity * 0.001;
                break;
            default:
                Etg_registerPurchTemp.QuantityInMetricTon = Etg_registerPurchTemp.Quantity; // Fallback
                break;
        }



        Etg_registerPurchTemp.insert();
    }
}

/// <summary>
///    inserting data useing parm query
/// </summary>
public void insertDataACF()
{
    QueryRun                        queryRun;
    VendTable                       vendAccountTable;
    VendTrans                       vendTrans;
    purchAgreementHeader            purchAgreementHeader;
    AgreementHeader                 agreementHeader;
    AgreementLine                   agreementLine;
    SalesAgreementHeader            salesAgreementHeader;
    ETG_purchTableTrade             ETG_purchTableTrade;
    VendPackingSlipJour             vendPackingSlipJour;
    VendPackingSlipTrans            vendPackingSlipTrans;
    VendInvoiceJour                 vendInvoiceJour;
    VendInvoiceTrans                vendInvoiceTrans;
    ETG_OrderType                   orderType;
    Query                           query = this.parmQuery();
    InventTrans                     inventTrans;
    ETG_PurchaseAgreementHeader     eTG_PurchaseAgreementHeader;
    ETG_AgreementType               AgreementType;
    DimensionAttributeValueSetStorage dimStorage;
    CompanyInfo                       companyInfo;
    InventTable                       inventTable;
    ETG_VendInvBillOfLading        vendInvBOL;
    ETGACFParameters                acfParameter;
    acfParameter = ETGACFParameters::find();


    utcFromDate = DateTimeUtil::newDateTime(fromDate, 0);
    utcToDate   = DateTimeUtil::newDateTime(toDate, 86400);

    while select vendInvoiceJour where vendInvoiceJour.InvoiceDate >= fromDate
                                   &&  vendInvoiceJour.InvoiceDate <= todate
                                   &&  vendInvoiceJour.purchasetype == purchasetype::Purch
        if(vendInvoiceJour)
    {
        while select vendInvBOL
            where vendInvBOL.VendInvRefRecId == vendInvoiceJour.RecId


            while select Qty, InventDimId, PackingSlipId,PurchUnit,ItemId, LineAmount_W, ValueMST
            from vendPackingSlipTrans
            where vendPackingSlipTrans.PackingSlipId == vendInvBOL.PackingSlipId
            && vendPackingSlipTrans.OrigPurchid == vendInvoiceJour.PurchId
        {
            select firstonly inventDim 
                where inventDim.InventDimId == vendPackingSlipTrans.InventDimId;

            select PurchPrice, PurchUnit from vendInvoiceTrans
                where vendInvoiceTrans.InvoiceId == vendInvoiceJour.InvoiceId
                  && vendInvoiceTrans.ItemId == vendPackingSlipTrans.ItemId;

            Etg_registerPurchTemp.clear();

            Etg_registerPurchTemp.InvoiceNumber       = vendInvoiceJour.InvoiceId;
            Etg_registerPurchTemp.Commodity          = vendPackingSlipTrans.ItemId;
            Etg_registerPurchTemp.GRNNumber            = vendPackingSlipTrans.PackingSlipId;

            Etg_registerPurchTemp.BillOfLadingNumber   = vendInvBOL.BLNumber;
            Etg_registerPurchTemp.Qty                  = vendPackingSlipTrans.Qty;
            Etg_registerPurchTemp.BatchNumber          = inventDim.InventBatchId;
            Etg_registerPurchTemp.Brand       = inventDim.InventStyleId;
            Etg_registerPurchTemp.Grade       = inventDim.configId;
            Etg_registerPurchTemp.Size        = inventDim.InventSizeId;
            Etg_registerPurchTemp.Site        = inventDim.InventSiteId;
            Etg_registerPurchTemp.Origin      = inventDim.InventColorId;
            Etg_registerPurchTemp.Location    = inventDim.wMSLocationId;
            Etg_registerPurchTemp.WareHouse   = inventDim.InventLocationId;

            Etg_registerPurchTemp.UnitPrice          = vendInvoiceTrans.PurchPrice;
            Etg_registerPurchTemp.ETGVoucher         = VendInvoiceJour.LedgerVoucher;
            Etg_registerPurchTemp.TransDate          = VendInvoiceJour.InvoiceDate;
            Etg_registerPurchTemp.Quantity           = vendPackingSlipTrans.Qty;
            Etg_registerPurchTemp.AmountInTransactionCurrency = vendPackingSlipTrans.LineAmount_W; //VendInvoiceJour.InvoiceAmount;
            Etg_registerPurchTemp.AmountInReportingCurrency  = vendPackingSlipTrans.ValueMST; //VendInvoiceJour.InvoiceAmountMST;
            Etg_registerPurchTemp.VendorCode         = VendInvoiceJour.InvoiceAccount;
            Etg_registerPurchTemp.VendorName         = vendTable::find(VendInvoiceJour.InvoiceAccount).name();
            Etg_registerPurchTemp.TaxAmount          = VendInvoiceJour.SumTax;
            Etg_registerPurchTemp.TaxGroup           = VendInvoiceJour.TaxGroup;
            Etg_registerPurchTemp.PONumber           = VendInvoiceJour.PurchId;
            Etg_registerPurchTemp.Currency           = VendInvoiceJour.CurrencyCode;
            Etg_registerPurchTemp.IncoTerms          = VendInvoiceJour.DlvTerm;

            select firstonly purchTable
            where purchTable.PurchId ==  VendInvoiceJour.PurchID;

            select firstonly ETG_purchTableTrade
            where ETG_purchTableTrade.PurchId == purchTable.PurchID;

            Etg_registerPurchTemp.Remarks           = ETG_purchTableTrade.Remarks;
            Etg_registerPurchTemp.PortofLoading     = ETG_purchTableTrade.PortOfLoadingDesc;
            Etg_registerPurchTemp.PortOfDischarge   = ETG_purchTableTrade.PortOfDischargeDesc;

            select firstonly purchAgreementHeader
            where purchAgreementHeader.RecId ==  purchTable.MatchingAgreement;

            select eTG_PurchaseAgreementHeader
            where eTG_PurchaseAgreementHeader.PurchAgreementId == PurchAgreementHeader.PurchNumberSequence;

            Etg_registerPurchTemp.PurchaseContractNumber   = purchAgreementHeader.PurchNumberSequence;
            Etg_registerPurchTemp.ContractOrderType        = eTG_PurchaseAgreementHeader.AgreementType;

            select firstonly inventTrans
            where inventTrans.InvoiceId ==   VendInvoiceJour.InvoiceId;

            select firstonly vendInvoiceTrans
            where vendInvoiceTrans.InvoiceId == vendInvoiceJour.InvoiceId ;

            Etg_registerPurchTemp.UOM                = vendInvoiceTrans.PurchUnit;

            Etg_registerPurchTemp.Location        = InventLocation::find(inventDim.InventLocationId).Name;
            Etg_registerPurchTemp.Vertical        =  ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(vendInvoiceJour.DefaultDimension, acfParameter.Vertical);
            Etg_registerPurchTemp.SubVertical     =   ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(vendInvoiceJour.DefaultDimension, acfParameter.BusinessUnit);
            Etg_registerPurchTemp.BusinessUnit    =  Etg_registerPurchTemp.SubVertical;

            select * from companyInfo where companyInfo.DataArea == curExt();

            Etg_registerPurchTemp.ETGCompanyName = companyInfo.name();
            Etg_registerPurchTemp.ETGCompanyLogo = FormLetter::companyLogo();

            select * from inventTable where inventTable.ItemId == inventTrans.ItemId;

            Etg_registerPurchTemp.ETGMainCommodity =  ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(vendInvoiceJour.DefaultDimension, acfParameter.MainCommodity);
            Etg_registerPurchTemp.ETGSubCommodity  =  ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(vendInvoiceJour.DefaultDimension, acfParameter.SubCommodity);

            Etg_registerPurchTemp.ETGVesselName    = ETG_purchTableTrade.VesselName;

            int num = mthOfYr(Etg_registerPurchTemp.TransDate);
            Etg_registerPurchTemp.ETGMonth = mthName(num);
            Etg_registerPurchTemp.ETGItemName      = EcoResProductTranslation::findByProductLanguage(InventTable::find(vendPackingSlipTrans.ItemId).Product, SystemParameters::getSystemLanguageId()).Name;




            Etg_registerPurchTemp.insert();
        }
    }
}

public Description getFinDimValue(DimensionDefault _defaultDimension, Name     _dimensionName)
    {
        DimensionAttributeValueSetStorage   dimStorage;
        DimensionAttribute                  dimAttribute;
        DimensionValue                      displayValue = "";
        Description                         dimDescription = "";
        int                                 i;

        dimStorage = DimensionAttributeValueSetStorage::find(_defaultDimension);
        for (i= 1 ; i<= dimStorage.elements() ; i++)
        {
            dimAttribute    = DimensionAttribute::find(dimStorage.getAttributeByIndex(i));

            if(dimAttribute.Name == _dimensionName)
            {
                displayValue    = dimStorage.getDisplayValueByIndex(i);
                dimDescription  = DimensionFinancialTag::findByFinancialTagCategoryAndValue(dimAttribute.financialTagCategory(), displayValue).Description;
                if (dimDescription == "")
                {
                    dimDescription  = this.getFinDimValueDescription(dimAttribute.ViewName, displayValue);
                }
            }
        }

        return  dimDescription;
    }

public Description getFinDimValueDescription(TableNameShort     _ViewName, DimensionValue   _displayValue)
    {
        DimAttributeInventTable         inventTable;
        DimAttributeHcmWorker           worker;
        DimAttributeCustTable           custTable;
        DimAttributeVendTable           dimVendTable;
        DimAttributeAssetTable          assetTable;
        DimAttributeOMBusinessUnit      businessUnit;
        DimAttributeOMCostCenter        costCenter;
        DimAttributeOMDepartment        department;
        Description                     dimDescription = "";

        switch (_ViewName)
        {
            case  "DimAttributeInventTable":
                select Name from inventTable
                where inventTable.value == _displayValue;
                dimDescription = inventTable.Name;
                break;
            case  "DimAttributeHcmWorker":
                select Name from worker
                where worker.value == _displayValue;
                dimDescription = worker.Name;
                break;
            case  "DimAttributeCustTable":
                select Name from custTable
                where custTable.value == _displayValue;
                dimDescription = custTable.Name;
                break;
            case  "DimAttributeVendTable":
                select Name from dimVendTable
                where dimVendTable.value == _displayValue;
                dimDescription = dimVendTable.Name;
                break;
            case  "DimAttributeAssetTable":
                select Name from assetTable
                where assetTable.value == _displayValue;
                dimDescription = assetTable.Name;
                break;
            case  "DimAttributeOMBusinessUnit":
                select Name from businessUnit
                where businessUnit.value == _displayValue;
                dimDescription = businessUnit.Name;
                break;
            case  "DimAttributeOMCostCenter":
                select Name from costCenter
                where costCenter.value == _displayValue;
                dimDescription = costCenter.Name;
                break;
            case  "DimAttributeOMDepartment":
                select Name from department
                where department.value == _displayValue;
                dimDescription = department.Name;
                break;
        }

        return      dimDescription;
    }

public boolean isDimensionIncludedInSet(Name        _setName, Name     _dimensionName)
    {
        FinancialDimensionSetEntity     financialDimensionSetEntity;

        select firstonly financialDimensionSetEntity
        where financialDimensionSetEntity.Name == _setName
        && (financialDimensionSetEntity.SegmentName01 == _dimensionName ||
        financialDimensionSetEntity.SegmentName02 == _dimensionName ||
        financialDimensionSetEntity.SegmentName03 == _dimensionName ||
        financialDimensionSetEntity.SegmentName04 == _dimensionName ||
        financialDimensionSetEntity.SegmentName05 == _dimensionName ||
        financialDimensionSetEntity.SegmentName06 == _dimensionName ||
        financialDimensionSetEntity.SegmentName07 == _dimensionName ||
        financialDimensionSetEntity.SegmentName08 == _dimensionName ||
        financialDimensionSetEntity.SegmentName09 == _dimensionName ||
        financialDimensionSetEntity.SegmentName10 == _dimensionName ||
        financialDimensionSetEntity.SegmentName11 == _dimensionName
        );

        return financialDimensionSetEntity.RecId;
    }
